{"meta": null, "content": [{"type": "text", "text": "{"content":"1: /* -*- Mode: C++; tab-width: 8; indent-tabs-mode: nil; c-basic-offset: 2 -*- */\n2: /* vim: set ts=8 sts=2 et sw=2 tw=80: */\n3: /* This Source Code Form is subject to the terms of the Mozilla Public\n4:  * License, v. 2.0. If a copy of the MPL was not distributed with this\n5:  * file, You can obtain one at http://mozilla.org/MPL/2.0/. */\n6: \n7: #include \"mozilla/Logging.h\"\n8: #include \"nsComponentManagerUtils.h\"\n9: #include \"nsContentUtils.h\"\n10: #include \"nsIConsoleService.h\"\n11: #include \"nsIObserverService.h\"\n12: #include \"nsIObserver.h\"\n13: #include \"nsIScriptError.h\"\n14: #include \"nsObserverService.h\"\n15: #include \"nsObserverList.h\"\n16: #include \"nsServiceManagerUtils.h\"\n17: #include \"nsThreadUtils.h\"\n18: #include \"nsEnumeratorUtils.h\"\n19: #include \"xpcpublic.h\"\n20: #include \"mozilla/AppShutdown.h\"\n21: #include \"mozilla/net/NeckoCommon.h\"\n22: #include \"mozilla/ProfilerLabels.h\"\n23: #include \"mozilla/ProfilerMarkers.h\"\n24: #include \"mozilla/TimeStamp.h\"\n25: #include \"mozilla/Try.h\"\n26: #include \"nsString.h\"\n27: \n28: // Log module for nsObserverService logging...\n29: //\n30: // To enable logging (see prlog.h for full details):\n31: //\n32: //    set MOZ_LOG=ObserverService:5\n33: //    set MOZ_LOG_FILE=service.log\n34: //\n35: // This enables LogLevel::Debug level information and places all output in\n36: // the file service.log.\n37: static mozilla::LazyLogModule sObserverServiceLog(\"ObserverService\");\n38: #define LOG(x) MOZ_LOG(sObserverServiceLog, mozilla::LogLevel::Debug, x)\n39: \n40: using namespace mozilla;\n41: \n42: NS_IMETHODIMP\n43: nsObserverService::CollectReports(nsIHandleReportCallback* aHandleReport,\n44:                                   nsISupports* aData, bool aAnonymize) {\n45:   struct SuspectObserver {\n46:     SuspectObserver(const char* aTopic, size_t aReferentCount)\n47:         : mTopic(aTopic), mReferentCount(aReferentCount) {}\n48:     const char* mTopic;\n49:     size_t mReferentCount;\n50:   };\n51: \n52:   size_t totalNumStrong = 0;\n53:   size_t totalNumWeakAlive = 0;\n54:   size_t totalNumWeakDead = 0;\n55:   nsTArray\u003cSuspectObserver\u003e suspectObservers;\n56: \n57:   for (auto iter = mObserverTopicTable.Iter(); !iter.Done(); iter.Next()) {\n58:     nsObserverList* observerList = iter.Get();\n59:     if (!observerList) {\n60:       continue;\n61:     }\n62: \n63:     size_t topicNumStrong = 0;\n64:     size_t topicNumWeakAlive = 0;\n65:     size_t topicNumWeakDead = 0;\n66: \n67:     nsMaybeWeakPtrArray\u003cnsIObserver\u003e\u0026 observers = observerList-\u003emObservers;\n68:     for (uint32_t i = 0; i \u003c observers.Length(); i++) {\n69:       if (observers[i].IsWeak()) {\n70:         nsCOMPtr\u003cnsIObserver\u003e ref = observers[i].GetValue();\n71:         if (ref) {\n72:           topicNumWeakAlive++;\n73:         } else {\n74:           topicNumWeakDead++;\n75:         }\n76:       } else {\n77:         topicNumStrong++;\n78:       }\n79:     }\n80: \n81:     totalNumStrong += topicNumStrong;\n82:     totalNumWeakAlive += topicNumWeakAlive;\n83:     totalNumWeakDead += topicNumWeakDead;\n84: \n85:     // Keep track of topics that have a suspiciously large number\n86:     // of referents (symptom of leaks).\n87:     size_t topicTotal = topicNumStrong + topicNumWeakAlive + topicNumWeakDead;\n88:     if (topicTotal \u003e kSuspectReferentCount) {\n89:       SuspectObserver suspect(observerList-\u003eGetKey(), topicTotal);\n90:       suspectObservers.AppendElement(suspect);\n91:     }\n92:   }\n93: \n94:   // These aren't privacy-sensitive and so don't need anonymizing.\n95:   for (uint32_t i = 0; i \u003c suspectObservers.Length(); i++) {\n96:     SuspectObserver\u0026 suspect = suspectObservers[i];\n97:     nsPrintfCString suspectPath(\"observer-service-suspect/referent(topic=%s)\",\n98:                                 suspect.mTopic);\n99:     aHandleReport-\u003eCallback(\n100:         /* process */ \"\"_ns, suspectPath, KIND_OTHER, UNITS_COUNT,\n101:         suspect.mReferentCount,\n102:         nsLiteralCString(\"A topic with a suspiciously large number of \"\n103:                          \"referents.  This may be symptomatic of a leak \"\n104:                          \"if the number of referents is high with \"\n105:                          \"respect to the number of windows.\"),\n106:         aData);\n107:   }\n108: \n109:   MOZ_COLLECT_REPORT(\n110:       \"observer-service/referent/strong\", KIND_OTHER, UNITS_COUNT,\n111:       totalNumStrong,\n112:       \"The number of strong references held by the observer service.\");\n113: \n114:   MOZ_COLLECT_REPORT(\n115:       \"observer-service/referent/weak/alive\", KIND_OTHER, UNITS_COUNT,\n116:       totalNumWeakAlive,\n117:       \"The number of weak references held by the observer service that are \"\n118:       \"still alive.\");\n119: \n120:   MOZ_COLLECT_REPORT(\n121:       \"observer-service/referent/weak/dead\", KIND_OTHER, UNITS_COUNT,\n122:       totalNumWeakDead,\n123:       \"The number of weak references held by the observer service that are \"\n124:       \"dead.\");\n125: \n126:   return NS_OK;\n127: }\n128: \n129: ////////////////////////////////////////////////////////////////////////////////\n130: // nsObserverService Implementation\n131: \n132: NS_IMPL_ISUPPORTS(nsObserverService, nsIObserverService, nsObserverService,\n133:                   nsIMemoryReporter)\n134: \n135: nsObserverService::nsObserverService() : mShuttingDown(false) {}\n136: \n137: nsObserverService::~nsObserverService(void) { Shutdown(); }\n138: \n139: void nsObserverService::RegisterReporter() { RegisterWeakMemoryReporter(this); }\n140: \n141: void nsObserverService::Shutdown() {\n142:   if (mShuttingDown) {\n143:     return;\n144:   }\n145: \n146:   mShuttingDown = true;\n147:   UnregisterWeakMemoryReporter(this);\n148:   mObserverTopicTable.Clear();\n149: }\n150: \n151: nsresult nsObserverService::Create(const nsIID\u0026 aIID, void** aInstancePtr) {\n152:   LOG((\"nsObserverService::Create()\"));\n153: \n154:   RefPtr\u003cnsObserverService\u003e os = new nsObserverService();\n155: \n156:   // The memory reporter can not be immediately registered here because\n157:   // the nsMemoryReporterManager may attempt to get the nsObserverService\n158:   // during initialization, causing a recursive GetService.\n159:   NS_DispatchToCurrentThread(\n160:       NewRunnableMethod(\"nsObserverService::RegisterReporter\", os,\n161:                         \u0026nsObserverService::RegisterReporter));\n162: \n163:   return os-\u003eQueryInterface(aIID, aInstancePtr);\n164: }\n165: \n166: nsresult nsObserverService::EnsureValidCall() const {\n167:   if (!NS_IsMainThread()) {\n168:     MOZ_CRASH(\"Using observer service off the main thread!\");\n169:     return NS_ERROR_UNEXPECTED;\n170:   }\n171: \n172:   if (mShuttingDown) {\n173:     NS_ERROR(\"Using observer service after XPCOM shutdown!\");\n174:     return NS_ERROR_ILLEGAL_DURING_SHUTDOWN;\n175:   }\n176: \n177:   return NS_OK;\n178: }\n179: \n180: nsresult nsObserverService::FilterHttpOnTopics(const char* aTopic) {\n181:   // Specifically allow some http-on-* observer notifications in the child\n182:   // process.\n183:   if (mozilla::net::IsNeckoChild() \u0026\u0026 !strncmp(aTopic, \"http-on-\", 8) \u0026\u0026\n184:       strcmp(aTopic, \"http-on-before-stop-request\") \u0026\u0026\n185:       strcmp(aTopic, \"http-on-failed-opening-request\") \u0026\u0026\n186:       strcmp(aTopic, \"http-on-resource-cache-response\") \u0026\u0026\n187:       strcmp(aTopic, \"http-on-opening-request\") \u0026\u0026\n188:       strcmp(aTopic, \"http-on-stop-request\")) {\n189:     nsCOMPtr\u003cnsIConsoleService\u003e console(\n190:         do_GetService(NS_CONSOLESERVICE_CONTRACTID));\n191:     nsCOMPtr\u003cnsIScriptError\u003e error(\n192:         do_CreateInstance(NS_SCRIPTERROR_CONTRACTID));\n193:     error-\u003eInit(u\"http-on-* observers only work in the parent process\"_ns,\n194:                 \"\"_ns, 0, 0, nsIScriptError::warningFlag,\n195:                 \"chrome javascript\"_ns, false /* from private window */,\n196:                 true /* from chrome context */);\n197:     console-\u003eLogMessage(error);\n198: \n199:     return NS_ERROR_NOT_IMPLEMENTED;\n200:   }\n201: \n202:   return NS_OK;\n203: }\n204: \n205: NS_IMETHODIMP\n206: nsObserverService::AddObserver(nsIObserver* aObserver, const char* aTopic,\n207:                                bool aOwnsWeak) {\n208:   LOG((\"nsObserverService::AddObserver(%p: %s, %s)\", (void*)aObserver, aTopic,\n209:        aOwnsWeak ? \"weak\" : \"strong\"));\n210: \n211:   MOZ_TRY(EnsureValidCall());\n212:   if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {\n213:     return NS_ERROR_INVALID_ARG;\n214:   }\n215: \n216:   MOZ_TRY(FilterHttpOnTopics(aTopic));\n217: \n218:   nsObserverList* observerList = mObserverTopicTable.PutEntry(aTopic);\n219:   if (!observerList) {\n220:     return NS_ERROR_OUT_OF_MEMORY;\n221:   }\n222: \n223:   return observerList-\u003eAddObserver(aObserver, aOwnsWeak);\n224: }\n225: \n226: NS_IMETHODIMP\n227: nsObserverService::RemoveObserver(nsIObserver* aObserver, const char* aTopic) {\n228:   LOG((\"nsObserverService::RemoveObserver(%p: %s)\", (void*)aObserver, aTopic));\n229: \n230:   if (mShuttingDown) {\n231:     // The service is shutting down. Let's ignore this call.\n232:     return NS_OK;\n233:   }\n234: \n235:   MOZ_TRY(EnsureValidCall());\n236:   if (NS_WARN_IF(!aObserver) || NS_WARN_IF(!aTopic)) {\n237:     return NS_ERROR_INVALID_ARG;\n238:   }\n239: \n240:   nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);\n241:   if (!observerList) {\n242:     return NS_ERROR_FAILURE;\n243:   }\n244: \n245:   return observerList-\u003eRemoveObserver(aObserver);\n246: }\n247: \n248: NS_IMETHODIMP\n249: nsObserverService::EnumerateObservers(const char* aTopic,\n250:                                       nsISimpleEnumerator** anEnumerator) {\n251:   LOG((\"nsObserverService::EnumerateObservers(%s)\", aTopic));\n252: \n253:   MOZ_TRY(EnsureValidCall());\n254:   if (NS_WARN_IF(!anEnumerator) || NS_WARN_IF(!aTopic)) {\n255:     return NS_ERROR_INVALID_ARG;\n256:   }\n257: \n258:   nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);\n259:   if (!observerList) {\n260:     return NS_NewEmptyEnumerator(anEnumerator);\n261:   }\n262: \n263:   observerList-\u003eGetObserverList(anEnumerator);\n264:   return NS_OK;\n265: }\n266: \n267: // Enumerate observers of aTopic and call Observe on each.\n268: NS_IMETHODIMP nsObserverService::NotifyObservers(nsISupports* aSubject,\n269:                                                  const char* aTopic,\n270:                                                  const char16_t* aSomeData) {\n271:   LOG((\"nsObserverService::NotifyObservers(%s)\", aTopic));\n272: \n273:   MOZ_TRY(EnsureValidCall());\n274:   if (NS_WARN_IF(!aTopic)) {\n275:     return NS_ERROR_INVALID_ARG;\n276:   }\n277: \n278:   MOZ_ASSERT(AppShutdown::IsNoOrLegalShutdownTopic(aTopic));\n279: \n280:   AUTO_PROFILER_MARKER_TEXT(\"NotifyObservers\", OTHER, MarkerStack::Capture(),\n281:                             nsDependentCString(aTopic));\n282:   AUTO_PROFILER_LABEL_DYNAMIC_CSTR_NONSENSITIVE(\n283:       \"nsObserverService::NotifyObservers\", OTHER, aTopic);\n284: \n285:   nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);\n286:   if (observerList) {\n287:     observerList-\u003eNotifyObservers(aSubject, aTopic, aSomeData);\n288:   }\n289: \n290:   return NS_OK;\n291: }\n292: \n293: NS_IMETHODIMP\n294: nsObserverService::UnmarkGrayStrongObservers() {\n295:   MOZ_TRY(EnsureValidCall());\n296: \n297:   nsCOMArray\u003cnsIObserver\u003e strongObservers;\n298:   for (auto iter = mObserverTopicTable.Iter(); !iter.Done(); iter.Next()) {\n299:     nsObserverList* aObserverList = iter.Get();\n300:     if (aObserverList) {\n301:       aObserverList-\u003eAppendStrongObservers(strongObservers);\n302:     }\n303:   }\n304: \n305:   for (uint32_t i = 0; i \u003c strongObservers.Length(); ++i) {\n306:     xpc_TryUnmarkWrappedGrayObject(strongObservers[i]);\n307:   }\n308: \n309:   return NS_OK;\n310: }\n311: \n312: bool nsObserverService::HasObservers(const char* aTopic) {\n313:   return mObserverTopicTable.Contains(aTopic);\n314: }\n315: \n316: namespace {\n317: \n318: class NotifyWhenScriptSafeRunnable : public mozilla::Runnable {\n319:  public:\n320:   NotifyWhenScriptSafeRunnable(nsIObserverService* aObs, nsISupports* aSubject,\n321:                                const char* aTopic, const char16_t* aData)\n322:       : mozilla::Runnable(\"NotifyWhenScriptSafeRunnable\"),\n323:         mObs(aObs),\n324:         mSubject(aSubject),\n325:         mTopic(aTopic) {\n326:     if (aData) {\n327:       mData.Assign(aData);\n328:     } else {\n329:       mData.SetIsVoid(true);\n330:     }\n331:   }\n332: \n333:   NS_IMETHOD Run() override {\n334:     const char16_t* data = mData.IsVoid() ? nullptr : mData.get();\n335:     return mObs-\u003eNotifyObservers(mSubject, mTopic.get(), data);\n336:   }\n337: \n338:  private:\n339:   nsCOMPtr\u003cnsIObserverService\u003e mObs;\n340:   nsCOMPtr\u003cnsISupports\u003e mSubject;\n341:   nsCString mTopic;\n342:   nsString mData;\n343: };\n344: \n345: }  // namespace\n346: \n347: nsresult nsIObserverService::NotifyWhenScriptSafe(nsISupports* aSubject,\n348:                                                   const char* aTopic,\n349:                                                   const char16_t* aData) {\n350:   if (nsContentUtils::IsSafeToRunScript()) {\n351:     return NotifyObservers(aSubject, aTopic, aData);\n352:   }\n353: \n354:   nsContentUtils::AddScriptRunner(MakeAndAddRef\u003cNotifyWhenScriptSafeRunnable\u003e(\n355:       this, aSubject, aTopic, aData));\n356:   return NS_OK;\n357: }\n358: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/firefox--871325b8@01dcdcebaca08ed5c32f8d50532752a063dc5ade/-/blob/xpcom/ds/nsObserverService.cpp"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: /* -*- Mode: C++; tab-width: 8; indent-tabs-mode: nil; c-basic-offset: 2 -*- */
