166: nsresult nsObserverService::EnsureValidCall() const {
167:   if (!NS_IsMainThread()) {
168:     MOZ_CRASH("Using observer service off the main thread!");
169:     return NS_ERROR_UNEXPECTED;
170:   }
171: 
172:   if (mShuttingDown) {
173:     NS_ERROR("Using observer service after XPCOM shutdown!");
174:     return NS_ERROR_ILLEGAL_DURING_SHUTDOWN;
175:   }
176: 
177:   return NS_OK;
178: }
