248: NS_IMETHODIMP
249: nsObserverService::EnumerateObservers(const char* aTopic,
250:                                       nsISimpleEnumerator** anEnumerator) {
251:   LOG(("nsObserverService::EnumerateObservers(%s)", aTopic));
252: 
253:   MOZ_TRY(EnsureValidCall());
254:   if (NS_WARN_IF(!anEnumerator) || NS_WARN_IF(!aTopic)) {
255:     return NS_ERROR_INVALID_ARG;
256:   }
257: 
258:   nsObserverList* observerList = mObserverTopicTable.GetEntry(aTopic);
259:   if (!observerList) {
260:     return NS_NewEmptyEnumerator(anEnumerator);
261:   }
262: 
263:   observerList->GetObserverList(anEnumerator);
264:   return NS_OK;
265: }
