72:  * and clear the slot containing the FinalizationEvent.
73:  */
74: already_AddRefed<FinalizationEvent> ExtractFinalizationEvent(
75:     JSObject* objSelf) {
76:   JS::Value slotEvent = JS::GetReservedSlot(objSelf, WITNESS_SLOT_EVENT);
77:   if (slotEvent.isUndefined()) {
78:     // Forget() has been called
79:     return nullptr;
80:   }
81: 
82:   JS_SetReservedSlot(objSelf, WITNESS_SLOT_EVENT, JS::UndefinedValue());
83: 
84:   return dont_AddRef(static_cast<FinalizationEvent*>(slotEvent.toPrivate()));
85: }
86: 
87: /**
88:  * Finalizer for instances of FinalizationWitness.
89:  *
90:  * Unless method Forget() has been called, the finalizer displays an error
91:  * message.
92:  */
93: void Finalize(JS::GCContext* gcx, JSObject* objSelf) {
94:   RefPtr<FinalizationEvent> event = ExtractFinalizationEvent(objSelf);
95:   if (event == nullptr || gShuttingDown) {
96:     // NB: event will be null if Forget() has been called
97:     return;
98:   }
99: 
100:   // Notify observers. Since we are executed during garbage-collection,
101:   // we need to dispatch the notification to the main thread.
102:   nsCOMPtr<nsIThread> mainThread = do_GetMainThread();
103:   if (mainThread) {
104:     mainThread->Dispatch(event.forget(), NS_DISPATCH_NORMAL);
105:   }
106:   // We may fail at dispatching to the main thread if we arrive too late
107:   // during shutdown. In that case, there is not much we can do.
108: }
109: 
110: static const JSClassOps sWitnessClassOps = {
111:     nullptr /* addProperty */,
112:     nullptr /* delProperty */,
113:     nullptr /* enumerate */,
114:     nullptr /* newEnumerate */,
115:     nullptr /* resolve */,
116:     nullptr /* mayResolve */,
117:     Finalize /* finalize */
118: };
119: 
120: static const JSClass sWitnessClass = {
121:     "FinalizationWitness",
122:     JSCLASS_HAS_RESERVED_SLOTS(WITNESS_INSTANCES_SLOTS) |
123:         JSCLASS_FOREGROUND_FINALIZE,
124:     &sWitnessClassOps};
125: 
126: bool IsWitness(JS::Handle<JS::Value> v) {
127:   return v.isObject() && JS::GetClass(&v.toObject()) == &sWitnessClass;
128: }
129: 
130: /**
131:  * JS method |forget()|
132:  *
133:  * === JS documentation
134:  *
135:  *  Neutralize the witness. Once this method is called, the witness will
136:  *  never report any error.
137:  */
138: bool ForgetImpl(JSContext* cx, const JS::CallArgs& args) {
139:   if (args.length() != 0) {
140:     JS_ReportErrorASCII(cx, "forget() takes no arguments");
141:     return false;
142:   }
143:   JS::Rooted<JS::Value> valSelf(cx, args.thisv());
144:   JS::Rooted<JSObject*> objSelf(cx, &valSelf.toObject());
145: 
146:   RefPtr<FinalizationEvent> event = ExtractFinalizationEvent(objSelf);
147:   if (event == nullptr) {
148:     JS_ReportErrorASCII(cx, "forget() called twice");
149:     return false;
150:   }
151: 
152:   args.rval().setUndefined();
153:   return true;
154: }
155: 
156: bool Forget(JSContext* cx, unsigned argc, JS::Value* vp) {
157:   JS::CallArgs args = CallArgsFromVp(argc, vp);
158:   return JS::CallNonGenericMethod<IsWitness, ForgetImpl>(cx, args);
159: }
160: 
161: static const JSFunctionSpec sWitnessClassFunctions[] = {
162:     JS_FN("forget", Forget, 0, JSPROP_READONLY | JSPROP_PERMANENT), JS_FS_END};
163: 
164: }  // namespace
165: 
166: NS_IMPL_ISUPPORTS(FinalizationWitnessService, nsIFinalizationWitnessService,
167:                   nsIObserver)
168: 
169: /**
170:  * Create a new Finalization Witness.
171:  *
172:  * A finalization witness is an object whose sole role is to notify
173:  * observers when it is gc-ed. Once the witness is created, call its
174:  * method |forget()| to prevent the observers from being notified.
175:  *
176:  * @param aTopic The notification topic.
177:  * @param aValue The notification value. Converted to a string.
178:  *
179:  * @constructor
180:  */
181: NS_IMETHODIMP
182: FinalizationWitnessService::Make(const char* aTopic, const char16_t* aValue,
183:                                  JSContext* aCx,
184:                                  JS::MutableHandle<JS::Value> aRetval) {
185:   JS::Rooted<JSObject*> objResult(aCx, JS_NewObject(aCx, &sWitnessClass));
186:   if (!objResult) {
187:     return NS_ERROR_OUT_OF_MEMORY;
188:   }
189:   if (!JS_DefineFunctions(aCx, objResult, sWitnessClassFunctions)) {
190:     return NS_ERROR_FAILURE;
191:   }
192: 
193:   RefPtr<FinalizationEvent> event = new FinalizationEvent(aTopic, aValue);
194: 
195:   // Transfer ownership of the addrefed |event| to |objResult|.
196:   JS_SetReservedSlot(objResult, WITNESS_SLOT_EVENT,
197:                      JS::PrivateValue(event.forget().take()));
198: 
199:   aRetval.setObject(*objResult);
200:   return NS_OK;
201: }
202: 
203: NS_IMETHODIMP
204: FinalizationWitnessService::Observe(nsISupports* aSubject, const char* aTopic,
205:                                     const char16_t* aValue) {
206:   MOZ_ASSERT(strcmp(aTopic, NS_XPCOM_SHUTDOWN_OBSERVER_ID) == 0);
207:   gShuttingDown = true;
208:   nsCOMPtr<nsIObserverService> obs = mozilla::services::GetObserverService();
209:   if (obs) {
210:     obs->RemoveObserver(this, NS_XPCOM_SHUTDOWN_OBSERVER_ID);
211:   }
212: 
213:   return NS_OK;
214: }
215: 
216: nsresult FinalizationWitnessService::Init() {
217:   nsCOMPtr<nsIObserverService> obs = mozilla::services::GetObserverService();
218:   if (!obs) {
219:     return NS_ERROR_FAILURE;
220:   }
221: 
222:   return obs->AddObserver(this, NS_XPCOM_SHUTDOWN_OBSERVER_ID, false);
223: }
224: 
225: }  // namespace mozilla
